// frontend/src/components/admin/AdminDashboard.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import UserManagement from './UserManagement';
import JobManagement from './JobManagement';
import VoucherManagement from './VoucherManagement';
import ReportsAnalytics from './ReportsAnalytics';
import { useAlert } from '../../contexts/AlertContext';
import './Admin.css';

const AdminDashboard = () => {
    const alert = useAlert();
    const { user } = useAuth();
    const [overview, setOverview] = useState(null);
    const [recentUsers, setRecentUsers] = useState([]);
    const [recentJobs, setRecentJobs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [activeTab, setActiveTab] = useState('overview');

    useEffect(() => {
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            // Use the correct endpoints
            const [overviewRes, usersRes, jobsRes] = await Promise.all([
                api.get('/admin/overview'),  // Changed from /admin/stats
                api.get('/admin/users'),
                api.get('/admin/jobs')
            ]);

            if (overviewRes.data.success) {
                setOverview(overviewRes.data.data);
            }
            if (usersRes.data.success) {
                setRecentUsers(usersRes.data.data.slice(0, 5));
            }
            if (jobsRes.data.success) {
                setRecentJobs(jobsRes.data.data.slice(0, 5));
            }
        } catch (error) {
            console.error('Error loading admin data:', error);
            setError('Failed to load dashboard data. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    if (user?.user_type !== 'admin') {
        return (
            <div className="admin-error">
                <h2>⛔ Access Denied</h2>
                <p>You don't have permission to view this page.</p>
                <Link to="/" className="btn-primary">Back Home</Link>
            </div>
        );
    }

    if (loading) {
        return <div className="loading-spinner">Loading dashboard...</div>;
    }

    // Safely access nested data
    const users = overview?.users || {};
    const jobs = overview?.jobs || {};
    const payments = overview?.payments || {};
    const vouchers = overview?.vouchers || {};

    return (
        <div className="admin-dashboard">
            <div className="admin-sidebar">
                <div className="sidebar-header">
                    <h2>👑 Admin Panel</h2>
                    <p>{user?.name}</p>
                </div>
                <nav className="sidebar-nav">
                    <button 
                        className={activeTab === 'overview' ? 'active' : ''}
                        onClick={() => setActiveTab('overview')}
                    >
                        📊 Overview
                    </button>
                    <button 
                        className={activeTab === 'users' ? 'active' : ''}
                        onClick={() => setActiveTab('users')}
                    >
                        👥 Users
                    </button>
                    <button 
                        className={activeTab === 'jobs' ? 'active' : ''}
                        onClick={() => setActiveTab('jobs')}
                    >
                        💼 Jobs
                    </button>
                    <button 
                        className={activeTab === 'vouchers' ? 'active' : ''}
                        onClick={() => setActiveTab('vouchers')}
                    >
                        🎫 Vouchers
                    </button>
                    <button 
                        className={activeTab === 'reports' ? 'active' : ''}
                        onClick={() => setActiveTab('reports')}
                    >
                        📈 Reports
                    </button>
                </nav>
            </div>

            <div className="admin-main">
                {activeTab === 'overview' && (
                    <div className="overview-tab">
                        <h1>Dashboard Overview</h1>

                        {error && <div className="admin-error">{error}</div>}

                        <div className="stats-grid">
                            <div className="stat-card">
                                <span className="stat-icon">👥</span>
                                <div className="stat-info">
                                    <span className="stat-value">{users.total_users || 0}</span>
                                    <span className="stat-label">Total Users</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">👷</span>
                                <div className="stat-info">
                                    <span className="stat-value">{users.total_workers || 0}</span>
                                    <span className="stat-label">Workers</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">🏠</span>
                                <div className="stat-info">
                                    <span className="stat-value">{users.total_clients || 0}</span>
                                    <span className="stat-label">Clients</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">💼</span>
                                <div className="stat-info">
                                    <span className="stat-value">{jobs.total_jobs || 0}</span>
                                    <span className="stat-label">Total Jobs</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">📝</span>
                                <div className="stat-info">
                                    <span className="stat-value">{jobs.posted_jobs || 0}</span>
                                    <span className="stat-label">Active Jobs</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">✅</span>
                                <div className="stat-info">
                                    <span className="stat-value">{jobs.completed_jobs || 0}</span>
                                    <span className="stat-label">Completed</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">🎫</span>
                                <div className="stat-info">
                                    <span className="stat-value">{vouchers.total_vouchers || 0}</span>
                                    <span className="stat-label">Vouchers Sold</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">💰</span>
                                <div className="stat-info">
                                    <span className="stat-value">
                                        R {overview?.payments?.total_revenue?.toLocaleString() || 0}
                                    </span>
                                    <span className="stat-label">Total Revenue</span>
                                </div>
                            </div>
                            <div className="stat-card">
                                <span className="stat-icon">💳</span>
                                <div className="stat-info">
                                    <span className="stat-value">
                                        R {overview?.payments?.job_payments?.toLocaleString() || 0}
                                    </span>
                                    <span className="stat-label">Job Payments</span>
                                </div>
                            </div>
                        </div>

                        {/* Growth Chart Section */}
                        {overview?.growth && overview.growth.length > 0 && (
                            <div className="chart-section">
                                <h2>Growth (Last 30 Days)</h2>
                                <div className="growth-chart">
                                    {overview.growth.slice(0, 7).map((item, index) => (
                                        <div key={index} className="chart-bar-container">
                                            <div 
                                                className="chart-bar" 
                                                style={{ 
                                                    height: `${Math.min(item.new_users * 20, 100)}px`,
                                                    background: '#FF6B35'
                                                }}
                                            >
                                                <span className="bar-value">{item.new_users}</span>
                                            </div>
                                            <span className="bar-label">
                                                {new Date(item.date).toLocaleDateString()}
                                            </span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Categories Section */}
                        {overview?.categories && overview.categories.length > 0 && (
                            <div className="categories-section">
                                <h2>Jobs by Category</h2>
                                <div className="categories-list">
                                    {overview.categories.slice(0, 5).map((cat, index) => (
                                        <div key={index} className="category-item">
                                            <span className="category-name">{cat.category}</span>
                                            <div className="progress-bar">
                                                <div 
                                                    className="progress-fill" 
                                                    style={{ 
                                                        width: `${(cat.count / overview.jobs.total_jobs) * 100}%` 
                                                    }}
                                                ></div>
                                            </div>
                                            <span className="category-count">{cat.count}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        <div className="recent-section">
                            <h2>Recent Users</h2>
                            <div className="recent-list">
                                {recentUsers.length === 0 ? (
                                    <p className="no-data">No recent users</p>
                                ) : (
                                    recentUsers.map(user => (
                                        <div key={user.id} className="recent-item">
                                            <span className="item-name">{user.name}</span>
                                            <span className="item-type">{user.user_type}</span>
                                            <span className="item-phone">{user.phone}</span>
                                            <span className={`item-status ${user.status}`}>
                                                {user.status}
                                            </span>
                                            <button 
                                                onClick={() => setActiveTab('users')}
                                                className="item-link"
                                            >
                                                Manage
                                            </button>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>

                        <div className="recent-section">
                            <h2>Recent Jobs</h2>
                            <div className="recent-list">
                                {recentJobs.length === 0 ? (
                                    <p className="no-data">No recent jobs</p>
                                ) : (
                                    recentJobs.map(job => (
                                        <div key={job.id} className="recent-item">
                                            <span className="item-name">{job.title}</span>
                                            <span className="item-type">{job.status}</span>
                                            <span className="item-township">{job.township}</span>
                                            <button 
                                                onClick={() => setActiveTab('jobs')}
                                                className="item-link"
                                            >
                                                Manage
                                            </button>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'users' && (
                    <UserManagement />
                )}

                {activeTab === 'jobs' && (
                    <JobManagement />
                )}

                {activeTab === 'vouchers' && (
                    <VoucherManagement />
                )}

                {activeTab === 'reports' && (
                    <ReportsAnalytics />
                )}
            </div>
        </div>
    );
};

export default AdminDashboard;
